{
  "name": "LifeLine ElectriGuard - ระบบแจ้งเตือนผู้ป่วยติดเตียงช่วงไฟดับ",
  "description": "ระบบจัดการและติดตามพิกัดผู้ป่วยติดเตียงสำหรับหน่วยงานการไฟฟ้า เพื่อเฝ้าระวังและช่วยเหลือกรณีไฟฟ้าขัดข้อง โดยเน้นการจัดลำดับความสำคัญตามความจำเป็นทางการแพทย์",
  "requestFramePermissions": [
    "geolocation"
  ]
}

export enum Priority {
  CRITICAL = 'CRITICAL', // ต้องใช้ไฟฟ้าตลอดเวลา (เครื่องช่วยหายใจ)
  HIGH = 'HIGH',         // อุปกรณ์พยุงชีพ (เครื่องดูดเสมหะ, เครื่องผลิตออกซิเจน)
  MEDIUM = 'MEDIUM',     // ผู้ป่วยติดเตียงทั่วไป (เตียงไฟฟ้า, แอร์ควบคุมอุณหภูมิ)
  LOW = 'LOW'            // ผู้ป่วยพักฟื้น
}

export enum PowerStatus {
  NORMAL = 'NORMAL',
  OUTAGE = 'OUTAGE',
  PLANNED_OUTAGE = 'PLANNED_OUTAGE'
}

export interface Patient {
  id: string;
  name: string;
  age: number;
  condition: string;
  equipment: string[];
  address: string;
  coordinates: {
    lat: number;
    lng: number;
  };
  contact: string;
  priority: Priority;
  status: PowerStatus;
  lastUpdated: string;
}

export interface OutageZone {
  id: string;
  areaName: string;
  startTime: string;
  estimatedRestoration: string;
  affectedPatientIds: string[];
}

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function assessPatientPriority(condition: string, equipment: string[]): Promise<{ priority: string; reason: string }> {
  const prompt = `ประเมินระดับความสำคัญของผู้ป่วยติดเตียงสำหรับหน่วยงานไฟฟ้า (PEA/MEA) 
  โดยพิจารณาจากอาการ: ${condition} และอุปกรณ์ที่ใช้: ${equipment.join(', ')}
  ระดับความสำคัญ: CRITICAL (วิกฤต - ต้องใช้ไฟฟ้าตลอดเวลาเพื่อพยุงชีพ), HIGH (สูง - มีอุปกรณ์สำคัญแต่มีแบตสำรองสั้นๆ), MEDIUM (ปานกลาง), LOW (ต่ำ)
  ตอบกลับเป็น JSON ภาษาไทย`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            priority: { type: Type.STRING, description: 'CRITICAL, HIGH, MEDIUM, or LOW' },
            reason: { type: Type.STRING, description: 'เหตุผลสั้นๆ ในการจัดระดับ' }
          },
          required: ['priority', 'reason']
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("AI Assessment failed:", error);
    return { priority: 'MEDIUM', reason: 'การประเมินผิดพลาด ใช้ค่าเริ่มต้น' };
  }
}

import React from 'react';
import { Patient, Priority } from '../types';

interface PatientMapProps {
  patients: Patient[];
  onSelectPatient: (p: Patient) => void;
}

const PatientMap: React.FC<PatientMapProps> = ({ patients, onSelectPatient }) => {
  return (
    <div className="relative w-full h-[600px] bg-slate-100 rounded-xl border-2 border-slate-200 overflow-hidden shadow-inner group">
      {/* Background Grid for Map Feel */}
      <div className="absolute inset-0 opacity-20 pointer-events-none" 
           style={{ backgroundImage: 'radial-gradient(#64748b 1px, transparent 1px)', backgroundSize: '30px 30px' }}></div>

      {/* Simulation of a real map with mock elements */}
      <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
        <div className="text-slate-400 font-bold text-4xl uppercase tracking-widest opacity-10">
          Command Center Area Map
        </div>
      </div>

      {/* Patient Markers */}
      {patients.map((p, idx) => {
        // Mock positioning based on lat/lng relative to a center point
        const top = 50 + (p.coordinates.lat - 13.75) * 5000;
        const left = 50 + (p.coordinates.lng - 100.5) * 500;

        return (
          <button
            key={p.id}
            onClick={() => onSelectPatient(p)}
            className={`absolute z-10 p-2 transition-all hover:scale-125 transform -translate-x-1/2 -translate-y-1/2 group`}
            style={{ top: `${top}%`, left: `${left}%` }}
          >
            <div className={`relative flex items-center justify-center`}>
              {/* Pulse effect for outages */}
              {p.status !== 'NORMAL' && (
                <div className="absolute inset-0 bg-red-500 rounded-full animate-ping opacity-75"></div>
              )}

              <div className={`w-8 h-8 rounded-full flex items-center justify-center shadow-lg border-2 border-white
                ${p.priority === Priority.CRITICAL ? 'bg-red-600' : 
                  p.priority === Priority.HIGH ? 'bg-orange-500' : 
                  'bg-blue-500'}`}
              >
                <span className="text-white text-xs font-bold">{idx + 1}</span>
              </div>

              {/* Tooltip-like label */}
              <div className="absolute top-10 left-1/2 -translate-x-1/2 bg-white px-2 py-1 rounded shadow text-[10px] font-bold whitespace-nowrap opacity-0 group-hover:opacity-100 transition-opacity">
                {p.name}
              </div>
            </div>
          </button>
        );
      })}

      {/* Control Overlay */}
      <div className="absolute bottom-4 left-4 bg-white p-3 rounded-lg shadow-lg text-xs space-y-2 border border-slate-200">
        <div className="font-bold border-bottom pb-1 mb-1">สัญลักษณ์ระดับความสำคัญ</div>
        <div className="flex items-center gap-2">
          <div className="w-3 h-3 rounded-full bg-red-600"></div> <span>วิกฤต (CRITICAL)</span>
        </div>
        <div className="flex items-center gap-2">
          <div className="w-3 h-3 rounded-full bg-orange-500"></div> <span>สูง (HIGH)</span>
        </div>
        <div className="flex items-center gap-2">
          <div className="w-3 h-3 rounded-full bg-blue-500"></div> <span>ปกติ (MEDIUM/LOW)</span>
        </div>
        <div className="flex items-center gap-2 mt-2 pt-2 border-t">
          <div className="w-3 h-3 rounded-full bg-red-500 animate-ping"></div> <span>เกิดเหตุไฟดับ</span>
        </div>
      </div>
    </div>
  );
};

export default PatientMap;

import React from 'react';
import { Patient, Priority, PowerStatus } from '../types';

interface PatientCardProps {
  patient: Patient;
  onUpdateStatus: (id: string, status: PowerStatus) => void;
}

const PatientCard: React.FC<PatientCardProps> = ({ patient, onUpdateStatus }) => {
  const isCritical = patient.priority === Priority.CRITICAL;
  const isOutage = patient.status !== PowerStatus.NORMAL;

  return (
    <div className={`p-4 rounded-xl border-l-4 shadow-sm transition-all hover:shadow-md bg-white
      ${isCritical ? 'border-l-red-600' : 'border-l-blue-500'} 
      ${isOutage ? 'ring-2 ring-red-400' : ''}`}
    >
      <div className="flex justify-between items-start mb-3">
        <div>
          <h3 className="font-bold text-lg text-slate-800">{patient.name}</h3>
          <p className="text-xs text-slate-500">อายุ: {patient.age} ปี | อัปเดตล่าสุด: {new Date(patient.lastUpdated).toLocaleTimeString()}</p>
        </div>
        <span className={`px-2 py-1 rounded text-[10px] font-bold uppercase
          ${isCritical ? 'bg-red-100 text-red-700' : 'bg-blue-100 text-blue-700'}`}>
          {patient.priority}
        </span>
      </div>

      <div className="space-y-2 mb-4">
        <p className="text-sm text-slate-600 leading-tight">
          <span className="font-semibold">อาการ:</span> {patient.condition}
        </p>
        <div className="flex flex-wrap gap-1">
          {patient.equipment.map(item => (
            <span key={item} className="bg-slate-100 text-slate-600 text-[10px] px-2 py-0.5 rounded-full border border-slate-200">
              {item}
            </span>
          ))}
        </div>
        <p className="text-sm text-slate-600">
          <span className="font-semibold">ที่อยู่:</span> {patient.address}
        </p>
        <p className="text-sm text-blue-600 font-semibold italic">
          <span className="font-semibold text-slate-600">ติดต่อ:</span> {patient.contact}
        </p>
      </div>

      <div className="flex gap-2">
        <button 
          onClick={() => onUpdateStatus(patient.id, PowerStatus.NORMAL)}
          className={`flex-1 py-1.5 rounded text-sm font-medium transition-colors
            ${patient.status === PowerStatus.NORMAL ? 'bg-green-100 text-green-700 cursor-default' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}
        >
          ไฟฟ้าปกติ
        </button>
        <button 
          onClick={() => onUpdateStatus(patient.id, PowerStatus.OUTAGE)}
          className={`flex-1 py-1.5 rounded text-sm font-medium transition-colors
            ${patient.status === PowerStatus.OUTAGE ? 'bg-red-600 text-white shadow-lg animate-pulse' : 'bg-red-50 text-red-600 hover:bg-red-100'}`}
        >
          แจ้งไฟดับ
        </button>
      </div>
    </div>
  );
};

export default PatientCard;

import React, { useState, useEffect, useCallback } from 'react';
import { Patient, Priority, PowerStatus } from './types';
import { MOCK_PATIENTS, EQUIPMENT_OPTIONS } from './constants';
import PatientMap from './components/PatientMap';
import PatientCard from './components/PatientCard';
import { assessPatientPriority } from './services/geminiService';

const App: React.FC = () => {
  const [patients, setPatients] = useState<Patient[]>(MOCK_PATIENTS as Patient[]);
  const [selectedPatient, setSelectedPatient] = useState<Patient | null>(null);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [isAssessing, setIsAssessing] = useState(false);

  // Form State
  const [newPatient, setNewPatient] = useState({
    name: '',
    age: '',
    condition: '',
    equipment: [] as string[],
    address: '',
    contact: '',
    lat: 13.75,
    lng: 100.5
  });

  const handleUpdateStatus = (id: string, status: PowerStatus) => {
    setPatients(prev => prev.map(p => 
      p.id === id ? { ...p, status, lastUpdated: new Date().toISOString() } : p
    ));
    if (selectedPatient?.id === id) {
      setSelectedPatient(prev => prev ? { ...prev, status, lastUpdated: new Date().toISOString() } : null);
    }
  };

  const handleAddPatient = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsAssessing(true);

    // Call AI to determine priority
    const assessment = await assessPatientPriority(newPatient.condition, newPatient.equipment);

    const patient: Patient = {
      id: Math.random().toString(36).substr(2, 9),
      name: newPatient.name,
      age: parseInt(newPatient.age) || 0,
      condition: newPatient.condition,
      equipment: newPatient.equipment,
      address: newPatient.address,
      contact: newPatient.contact,
      coordinates: { lat: newPatient.lat, lng: newPatient.lng },
      priority: assessment.priority as Priority,
      status: PowerStatus.NORMAL,
      lastUpdated: new Date().toISOString()
    };

    setPatients(prev => [patient, ...prev]);
    setIsFormOpen(false);
    setIsAssessing(false);
    // Reset form
    setNewPatient({ name: '', age: '', condition: '', equipment: [], address: '', contact: '', lat: 13.75, lng: 100.5 });
  };

  const toggleEquipment = (item: string) => {
    setNewPatient(prev => ({
      ...prev,
      equipment: prev.equipment.includes(item) 
        ? prev.equipment.filter(e => e !== item)
        : [...prev.equipment, item]
    }));
  };

  const totalCritical = patients.filter(p => p.priority === Priority.CRITICAL).length;
  const currentOutages = patients.filter(p => p.status === PowerStatus.OUTAGE).length;

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Header */}
      <header className="bg-slate-900 text-white shadow-xl sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex flex-col sm:flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-3">
            <div className="bg-yellow-500 p-2 rounded-lg">
              <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m6 3 7 7l-2 2l8 8"/><path d="m18 21l-7-7l2-2l-8-8"/></svg>
            </div>
            <div>
              <h1 className="text-xl font-bold tracking-tight">LifeLine ElectriGuard</h1>
              <p className="text-xs text-slate-400">ระบบเฝ้าระวังผู้ป่วยกลุ่มเปราะบางสำหรับการไฟฟ้า</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <div className="flex gap-4 text-center">
              <div className="bg-slate-800 px-3 py-1 rounded-md">
                <p className="text-[10px] text-slate-400 uppercase font-bold">ผู้ป่วยวิกฤต</p>
                <p className="text-lg font-bold text-red-500">{totalCritical}</p>
              </div>
              <div className="bg-slate-800 px-3 py-1 rounded-md">
                <p className="text-[10px] text-slate-400 uppercase font-bold">เกิดไฟดับ</p>
                <p className="text-lg font-bold text-yellow-500">{currentOutages}</p>
              </div>
            </div>
            <button 
              onClick={() => setIsFormOpen(true)}
              className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg font-bold transition-all shadow-lg flex items-center gap-2"
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="M12 5v14"/></svg>
              เพิ่มข้อมูลผู้ป่วย
            </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 max-w-7xl mx-auto w-full px-4 sm:px-6 lg:px-8 py-8 grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* Sidebar / List */}
        <div className="lg:col-span-4 flex flex-col gap-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <h2 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="text-blue-500"><path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M22 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg>
              รายการผู้ป่วยในเขตรับผิดชอบ
            </h2>
            <div className="space-y-4 max-h-[700px] overflow-y-auto pr-2 custom-scrollbar">
              {patients.length === 0 ? (
                <div className="text-center py-10 text-slate-400">ยังไม่มีข้อมูลผู้ป่วย</div>
              ) : (
                patients.map(p => (
                  <PatientCard 
                    key={p.id} 
                    patient={p} 
                    onUpdateStatus={handleUpdateStatus} 
                  />
                ))
              )}
            </div>
          </div>
        </div>

        {/* Map View */}
        <div className="lg:col-span-8 space-y-6">
          <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-200">
            <div className="flex justify-between items-center mb-4">
              <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="text-red-500"><path d="M20 10c0 6-8 12-8 12s-8-6-8-12a8 8 0 0 1 16 0Z"/><circle cx="12" cy="10" r="3"/></svg>
                แผนที่แสดงพิกัดผู้ป่วย
              </h2>
              <div className="text-xs text-slate-500">
                สถานะ: <span className="text-green-500 font-bold">ออนไลน์</span>
              </div>
            </div>
            <PatientMap patients={patients} onSelectPatient={setSelectedPatient} />
          </div>

          {/* Emergency Alert Section */}
          {currentOutages > 0 && (
            <div className="bg-red-50 border-2 border-red-200 rounded-2xl p-6 animate-pulse">
              <div className="flex items-center gap-4 mb-4">
                <div className="bg-red-600 text-white p-2 rounded-full">
                  <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m21.73 18l-8-14a2 2 0 0 0-3.48 0l-8 14A2 2 0 0 0 4 21h16a2 2 0 0 0 1.73-3Z"/><path d="M12 9v4"/><path d="M12 17h.01"/></svg>
                </div>
                <div>
                  <h3 className="text-xl font-bold text-red-700 uppercase">ตรวจพบเหตุไฟฟ้าขัดข้อง!</h3>
                  <p className="text-red-600">มีผู้ป่วยกลุ่มเสี่ยงได้รับผลกระทบ {currentOutages} ราย</p>
                </div>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {patients.filter(p => p.status === PowerStatus.OUTAGE).map(p => (
                  <div key={p.id} className="bg-white p-3 rounded-lg border border-red-200 shadow-sm flex justify-between items-center">
                    <div>
                      <p className="font-bold text-slate-800">{p.name}</p>
                      <p className="text-xs text-red-600">{p.priority === Priority.CRITICAL ? 'วิกฤต: ต้องได้รับความช่วยเหลือทันที' : 'ความสำคัญสูง'}</p>
                    </div>
                    <button 
                      className="bg-red-600 text-white text-xs px-3 py-1.5 rounded font-bold"
                      onClick={() => alert(`แจ้งหน่วยเคลื่อนที่เร็วช่วยเหลือคุณ ${p.name} ที่ ${p.address}`)}
                    >
                      ส่งหน่วยช่วยเหลือ
                    </button>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </main>

      {/* Footer */}
      <footer className="bg-white border-t border-slate-200 py-6 text-center text-slate-400 text-sm">
        &copy; {new Date().getFullYear()} LifeLine ElectriGuard - ระบบสนับสนุนการตัดสินใจเพื่อความปลอดภัยของผู้ป่วย
      </footer>

      {/* Registration Modal */}
      {isFormOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center z-[100] p-4">
          <div className="bg-white rounded-2xl shadow-2xl max-w-2xl w-full max-h-[90vh] overflow-y-auto flex flex-col">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center sticky top-0 bg-white z-10">
              <h2 className="text-2xl font-bold text-slate-800">ลงทะเบียนผู้ป่วยใหม่</h2>
              <button onClick={() => !isAssessing && setIsFormOpen(false)} className="text-slate-400 hover:text-slate-600 p-2">
                <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M18 6 6 18"/><path d="m6 6 12 12"/></svg>
              </button>
            </div>

            <form onSubmit={handleAddPatient} className="p-8 space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-sm font-bold text-slate-700">ชื่อ-นามสกุล</label>
                  <input 
                    required 
                    className="w-full px-4 py-2 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none"
                    value={newPatient.name}
                    onChange={e => setNewPatient({...newPatient, name: e.target.value})}
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-bold text-slate-700">อายุ (ปี)</label>
                  <input 
                    type="number" 
                    required 
                    className="w-full px-4 py-2 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 outline-none"
                    value={newPatient.age}
                    onChange={e => setNewPatient({...newPatient, age: e.target.value})}
                  />
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-sm font-bold text-slate-700">อาการและโรคประจำตัว (AI จะใช้ประเมินความสำคัญ)</label>
                <textarea 
                  required 
                  className="w-full px-4 py-2 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 outline-none h-24"
                  placeholder="เช่น ผู้ป่วยติดเตียง เป็นอัมพาตครึ่งซีก ไม่สามารถหายใจเองได้ ต้องพึ่งพาเครื่องมือแพทย์..."
                  value={newPatient.condition}
                  onChange={e => setNewPatient({...newPatient, condition: e.target.value})}
                />
              </div>

              <div className="space-y-3">
                <label className="text-sm font-bold text-slate-700 block">อุปกรณ์ที่ต้องใช้ไฟฟ้า</label>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
                  {EQUIPMENT_OPTIONS.map(item => (
                    <label key={item} className={`flex items-center gap-2 p-2 rounded-lg border cursor-pointer transition-colors
                      ${newPatient.equipment.includes(item) ? 'bg-blue-50 border-blue-500' : 'hover:bg-slate-50 border-slate-200'}`}>
                      <input 
                        type="checkbox" 
                        className="hidden" 
                        checked={newPatient.equipment.includes(item)}
                        onChange={() => toggleEquipment(item)}
                      />
                      <div className={`w-4 h-4 rounded-sm border flex items-center justify-center
                        ${newPatient.equipment.includes(item) ? 'bg-blue-600 border-blue-600' : 'bg-white border-slate-300'}`}>
                        {newPatient.equipment.includes(item) && <svg className="text-white" width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><path d="M20 6 9 17l-5-5"/></svg>}
                      </div>
                      <span className="text-xs font-medium text-slate-600">{item}</span>
                    </label>
                  ))}
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-sm font-bold text-slate-700">ที่อยู่จัดส่งกระแสไฟฟ้า</label>
                <input 
                  required 
                  className="w-full px-4 py-2 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 outline-none"
                  value={newPatient.address}
                  onChange={e => setNewPatient({...newPatient, address: e.target.value})}
                />
              </div>

              <div className="space-y-2">
                <label className="text-sm font-bold text-slate-700">เบอร์ติดต่อกรณีฉุกเฉิน</label>
                <input 
                  required 
                  className="w-full px-4 py-2 rounded-lg border border-slate-300 focus:ring-2 focus:ring-blue-500 outline-none"
                  placeholder="081-XXX-XXXX"
                  value={newPatient.contact}
                  onChange={e => setNewPatient({...newPatient, contact: e.target.value})}
                />
              </div>

              <div className="bg-slate-50 p-4 rounded-xl border border-dashed border-slate-300">
                <p className="text-xs text-slate-500 mb-2">พิกัดทางภูมิศาสตร์ (Mock Location)</p>
                <div className="grid grid-cols-2 gap-4">
                  <div className="flex items-center gap-2">
                    <span className="text-[10px] text-slate-400 font-bold">LAT:</span>
                    <input type="number" step="0.0001" className="bg-transparent border-b border-slate-300 outline-none text-sm w-full" value={newPatient.lat} onChange={e => setNewPatient({...newPatient, lat: parseFloat(e.target.value)})}/>
                  </div>
                  <div className="flex items-center gap-2">
                    <span className="text-[10px] text-slate-400 font-bold">LNG:</span>
                    <input type="number" step="0.0001" className="bg-transparent border-b border-slate-300 outline-none text-sm w-full" value={newPatient.lng} onChange={e => setNewPatient({...newPatient, lng: parseFloat(e.target.value)})}/>
                  </div>
                </div>
              </div>

              <button 
                type="submit" 
                disabled={isAssessing}
                className={`w-full py-4 rounded-xl text-white font-bold text-lg shadow-xl transition-all
                  ${isAssessing ? 'bg-slate-400 cursor-not-allowed' : 'bg-blue-600 hover:bg-blue-700 active:scale-95'}`}
              >
                {isAssessing ? (
                  <span className="flex items-center justify-center gap-3">
                    <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                    AI กำลังประเมินระดับความสำคัญ...
                  </span>
                ) : 'บันทึกข้อมูลและลงทะเบียน'}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

