import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Patient, Priority, PowerStatus } from './types';
import { MOCK_PATIENTS, EQUIPMENT_OPTIONS } from './constants';
import PatientMap from './components/PatientMap';
import PatientCard from './components/PatientCard';
import { assessPatientPriority } from './services/geminiService';

const App: React.FC = () => {
  const [patients, setPatients] = useState<Patient[]>(MOCK_PATIENTS as Patient[]);
  const [selectedPatient, setSelectedPatient] = useState<Patient | null>(null);
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [isAssessing, setIsAssessing] = useState(false);
  const [isSimulationEnabled, setIsSimulationEnabled] = useState(true);

  // Form State
  const [newPatient, setNewPatient] = useState({
    name: '',
    age: '',
    condition: '',
    equipment: [] as string[],
    address: '',
    contact: '',
    lat: 13.75,
    lng: 100.5
  });

  // Simulation Logic: Randomly trigger outages for patients
  useEffect(() => {
    if (!isSimulationEnabled) return;

    const interval = setInterval(() => {
      setPatients(prev => {
        // Find a healthy patient and randomly make them have an outage (15% chance per tick)
        if (Math.random() > 0.15) return prev;

        const normalPatients = prev.filter(p => p.status === PowerStatus.NORMAL);
        if (normalPatients.length === 0) return prev;

        const randomIndex = Math.floor(Math.random() * normalPatients.length);
        const targetId = normalPatients[randomIndex].id;

        // Outage duration between 5 and 30 minutes
        const durationMinutes = Math.floor(Math.random() * 25) + 5;
        const restorationTime = new Date();
        restorationTime.setMinutes(restorationTime.getMinutes() + durationMinutes);

        console.log(`[SIMULATION] Random outage for ${normalPatients[randomIndex].name} for ${durationMinutes} mins`);

        return prev.map(p => 
          p.id === targetId 
            ? { 
                ...p, 
                status: PowerStatus.OUTAGE, 
                outageStartTime: new Date().toISOString(),
                estimatedRestorationTime: restorationTime.toISOString(),
                lastUpdated: new Date().toISOString() 
              } 
            : p
        );
      });
    }, 20000); // Check every 20 seconds

    return () => clearInterval(interval);
  }, [isSimulationEnabled]);

  const handleUpdateStatus = (id: string, status: PowerStatus) => {
    const outageStartTime = status === PowerStatus.OUTAGE ? new Date().toISOString() : undefined;
    const estimatedRestorationTime = status === PowerStatus.OUTAGE 
      ? new Date(new Date().getTime() + 45 * 60000).toISOString() // Default 45 mins for manual
      : undefined;

    setPatients(prev => prev.map(p => 
      p.id === id ? { 
        ...p, 
        status, 
        lastUpdated: new Date().toISOString(),
        outageStartTime,
        estimatedRestorationTime
      } : p
    ));

    if (selectedPatient?.id === id) {
      setSelectedPatient(prev => prev ? { 
        ...prev, 
        status, 
        lastUpdated: new Date().toISOString(),
        outageStartTime,
        estimatedRestorationTime
      } : null);
    }
  };

  const handleAddPatient = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsAssessing(true);

    // Call AI to determine priority
    const assessment = await assessPatientPriority(newPatient.condition, newPatient.equipment);

    const patient: Patient = {
      id: Math.random().toString(36).substr(2, 9),
      name: newPatient.name,
      age: parseInt(newPatient.age) || 0,
      condition: newPatient.condition,
      equipment: newPatient.equipment,
      address: newPatient.address,
      contact: newPatient.contact,
      coordinates: { lat: newPatient.lat, lng: newPatient.lng },
      priority: assessment.priority as Priority,
      status: PowerStatus.NORMAL,
      lastUpdated: new Date().toISOString()
    };

    setPatients(prev => [patient, ...prev]);
    setIsFormOpen(false);
    setIsAssessing(false);
    // Reset form
    setNewPatient({ name: '', age: '', condition: '', equipment: [], address: '', contact: '', lat: 13.75, lng: 100.5 });
  };

  const toggleEquipment = (item: string) => {
    setNewPatient(prev => ({
      ...prev,
      equipment: prev.equipment.includes(item) 
        ? prev.equipment.filter(e => e !== item)
        : [...prev.equipment, item]
    }));
  };

  const totalCritical = useMemo(() => patients.filter(p => p.priority === Priority.CRITICAL).length, [patients]);
  const currentOutagesCount = useMemo(() => patients.filter(p => p.status === PowerStatus.OUTAGE).length, [patients]);
  const affectedPatients = useMemo(() => patients.filter(p => p.status === PowerStatus.OUTAGE), [patients]);

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-['Anuphan']">
      {/* Header */}
      <header className="bg-slate-900 text-white shadow-xl sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex flex-col sm:flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-3">
            <div className="bg-yellow-500 p-2 rounded-lg shadow-[0_0_15px_rgba(234,179,8,0.4)]">
              <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m6 3 7 7l-2 2l8 8"/><path d="m18 21l-7-7l2-2l-8-8"/></svg>
            </div>
            <div>
              <h1 className="text-xl font-bold tracking-tight">LifeLine ElectriGuard</h1>
              <p className="text-[10px] text-slate-400 uppercase tracking-widest font-bold">Real-time Patient Power Monitor</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <div className="flex gap-2">
              <div className="bg-slate-800 px-3 py-1.5 rounded-lg border border-slate-700 flex flex-col items-center min-w-[80px]">
                <p className="text-[9px] text-slate-400 uppercase font-black">วิกฤต</p>
                <p className="text-xl font-black text-red-500 leading-none mt-1">{totalCritical}</p>
              </div>
              <div className={`bg-slate-800 px-3 py-1.5 rounded-lg border flex flex-col items-center min-w-[80px] transition-all
                ${currentOutagesCount > 0 ? 'border-yellow-500/50 shadow-[0_0_10px_rgba(234,179,8,0.2)]' : 'border-slate-700'}`}>
                <p className="text-[9px] text-slate-400 uppercase font-black">ไฟดับ</p>
                <p className={`text-xl font-black leading-none mt-1 ${currentOutagesCount > 0 ? 'text-yellow-500 animate-pulse' : 'text-slate-500'}`}>
                  {currentOutagesCount}
                </p>
              </div>
            </div>

            <div className="h-10 w-px bg-slate-700 mx-1 hidden sm:block"></div>

            <div className="flex items-center gap-3">
              <button 
                onClick={() => setIsSimulationEnabled(!isSimulationEnabled)}
                className={`text-[10px] font-bold px-2 py-1 rounded transition-all border
                  ${isSimulationEnabled ? 'bg-green-500/10 text-green-400 border-green-500/20' : 'bg-slate-800 text-slate-500 border-slate-700'}`}
              >
                SIMULATION: {isSimulationEnabled ? 'ON' : 'OFF'}
              </button>
              <button 
                onClick={() => setIsFormOpen(true)}
                className="bg-blue-600 hover:bg-blue-700 text-white px-5 py-2.5 rounded-xl font-bold transition-all shadow-lg flex items-center gap-2 text-sm"
              >
                <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="M12 5v14"/></svg>
                ลงทะเบียน
              </button>
            </div>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 max-w-7xl mx-auto w-full px-4 sm:px-6 lg:px-8 py-8 grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* Sidebar / List */}
        <div className="lg:col-span-4 flex flex-col gap-6 order-2 lg:order-1">
          <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-200">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-lg font-black text-slate-800 flex items-center gap-2">
                <div className="w-8 h-8 rounded-lg bg-blue-50 text-blue-600 flex items-center justify-center">
                  <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M22 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg>
                </div>
                รายชื่อผู้ป่วย
              </h2>
              <span className="text-[10px] font-bold px-2 py-0.5 bg-slate-100 text-slate-500 rounded-full uppercase tracking-tighter">
