              ) : (
                [...patients].sort((a,b) => {
                  if (a.status === PowerStatus.OUTAGE && b.status !== PowerStatus.OUTAGE) return -1;
                  if (b.status === PowerStatus.OUTAGE && a.status !== PowerStatus.OUTAGE) return 1;
                  return 0;
