import React from 'react';
import { Patient, Priority, PlannedOutageZone } from '../types';

interface PatientMapProps {
  patients: Patient[];
  onSelectPatient: (p: Patient) => void;
  plannedZone: PlannedOutageZone;
  onMapClick?: (lat: number, lng: number) => void;
  isPlanningMode: boolean;
}

const PatientMap: React.FC<PatientMapProps> = ({ 
  patients, 
  onSelectPatient, 
  plannedZone, 
  onMapClick,
  isPlanningMode
}) => {
  // Simple coordinate to percentage conversion for mock map
  const getPos = (lat: number, lng: number) => {
    const top = 50 + (lat - 13.75) * 5000;
    const left = 50 + (lng - 100.5) * 500;
    return { top, left };
  };

  const handleContainerClick = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!isPlanningMode || !onMapClick) return;

    // Reverse mock projection for simulation purposes
    const rect = e.currentTarget.getBoundingClientRect();
    const x = ((e.clientX - rect.left) / rect.width) * 100;
    const y = ((e.clientY - rect.top) / rect.height) * 100;

    const lng = (x - 50) / 500 + 100.5;
    const lat = (y - 50) / 5000 + 13.75;

    onMapClick(lat, lng);
  };

  return (
    <div 
      onClick={handleContainerClick}
      className={`relative w-full h-[600px] bg-slate-900 rounded-[40px] border-4 border-slate-800 overflow-hidden shadow-2xl group transition-all
        ${isPlanningMode ? 'cursor-crosshair ring-8 ring-yellow-400/10' : ''}`}
    >
      {/* High-Tech Grid Background */}
      <div className="absolute inset-0 opacity-10 pointer-events-none" 
           style={{ 
             backgroundImage: 'linear-gradient(#334155 1px, transparent 1px), linear-gradient(90deg, #334155 1px, transparent 1px)', 
             backgroundSize: '40px 40px' 
           }}></div>

      {/* Dashboard Text */}
      <div className="absolute inset-0 flex items-center justify-center pointer-events-none select-none">
        <div className="text-white font-black text-6xl uppercase tracking-[1.5em] opacity-[0.03]">
          Command Center
        </div>
      </div>

      {/* Planned Outage Visualization - Realistic Radar Style */}
      {plannedZone.isActive && (
        <div 
          className="absolute border border-yellow-400/50 rounded-full transition-all duration-500 pointer-events-none overflow-hidden"
          style={{
            top: `${getPos(plannedZone.center.lat, plannedZone.center.lng).top}%`,
            left: `${getPos(plannedZone.center.lat, plannedZone.center.lng).left}%`,
            width: `${plannedZone.radiusKm * 150}px`,
            height: `${plannedZone.radiusKm * 150}px`,
            transform: 'translate(-50%, -50%)',
            background: 'radial-gradient(circle, rgba(234, 179, 8, 0.15) 0%, rgba(234, 179, 8, 0.05) 70%, transparent 100%)',
            boxShadow: '0 0 60px rgba(234, 179, 8, 0.2), inset 0 0 30px rgba(234, 179, 8, 0.1)'
          }}
        >
          {/* Radar Sweep Animation */}
          <div className="absolute inset-0 bg-conic-radar animate-radar-sweep opacity-30"></div>

          {/* Concentric Circles for distance */}
          <div className="absolute inset-0 border border-yellow-400/20 rounded-full m-8"></div>
          <div className="absolute inset-0 border border-yellow-400/20 rounded-full m-16"></div>

          <div className="absolute top-0 left-1/2 -translate-x-1/2 -translate-y-full mb-2 bg-yellow-500 text-white text-[10px] font-black px-3 py-1 rounded-full whitespace-nowrap shadow-lg">
            AFFECTED ZONE: {plannedZone.radiusKm} KM
          </div>
        </div>
      )}

      {/* Patient Markers */}
      {patients.map((p, idx) => {
        const { top, left } = getPos(p.coordinates.lat, p.coordinates.lng);
        const isAffected = plannedZone.isActive && (
          Math.sqrt(Math.pow(p.coordinates.lat - plannedZone.center.lat, 2) + Math.pow(p.coordinates.lng - plannedZone.center.lng, 2)) < (plannedZone.radiusKm * 0.01)
        );

        return (
          <button
            key={p.id}
            onClick={(e) => { e.stopPropagation(); onSelectPatient(p); }}
            className={`absolute z-10 p-2 transition-all hover:scale-125 transform -translate-x-1/2 -translate-y-1/2`}
            style={{ top: `${top}%`, left: `${left}%` }}
          >
            <div className="relative flex items-center justify-center">
              {p.status !== 'NORMAL' && (
                <div className="absolute inset-0 bg-red-500 rounded-full animate-ping opacity-75"></div>
              )}
              {isAffected && !isPlanningMode && (
                <div className="absolute -inset-4 border-2 border-yellow-400/40 rounded-full animate-spin-slow"></div>
              )}

              <div className={`w-10 h-10 rounded-2xl flex items-center justify-center shadow-2xl border-2 transition-all
                ${p.priority === Priority.CRITICAL ? 'bg-red-600 border-red-400' : 
                  p.priority === Priority.HIGH ? 'bg-orange-500 border-orange-300' : 
                  'bg-blue-600 border-blue-400'}
                ${isAffected ? 'ring-[6px] ring-yellow-400/30 scale-110' : 'border-white/20'}`}
              >
                <span className="text-white text-xs font-black">{idx + 1}</span>
              </div>
            </div>
          </button>
        );
      })}

      {/* Map Control UI */}
      <div className="absolute top-8 left-8 flex flex-col gap-4">
        <div className="bg-slate-800/80 backdrop-blur-xl px-5 py-3 rounded-3xl shadow-2xl border border-white/10 flex items-center gap-4">
           <div className="flex flex-col">
             <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Operation Status</span>
             <div className="flex items-center gap-2">
                <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>
                <span className="text-xs font-bold text-white uppercase">Sector Active</span>
             </div>
           </div>
        </div>
      </div>

      {/* Legend */}
      <div className="absolute bottom-8 right-8 bg-slate-800/90 backdrop-blur-2xl p-6 rounded-[32px] shadow-2xl text-[10px] space-y-4 border border-white/10 min-w-[240px]">
        <div className="font-black text-white border-b border-white/10 pb-3 mb-1 uppercase tracking-widest flex items-center justify-between">
           <span>Map Intelligence</span>
           <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M21 12V7a2 2 0 0 0-2-2H5a2 2 0 0 0-2 2v10a2 2 0 0 0 2 2h7"/><path d="M16 5V3"/><path d="M8 5V3"/><path d="M3 9h16"/><path d="M21 21l-3.5-3.5"/><circle cx="15.5" cy="15.5" r="3.5"/></svg>
        </div>
        <div className="grid grid-cols-1 gap-3">
          <div className="flex items-center gap-4 group">
            <div className="w-4 h-4 rounded-lg bg-red-600 shadow-[0_0_10px_rgba(220,38,38,0.5)] transition-transform group-hover:scale-110"></div> 
            <span className="font-bold text-slate-300">วิกฤต (Life Support Required)</span>
          </div>
          <div className="flex items-center gap-4 group">
            <div className="w-4 h-4 rounded-lg bg-orange-500 shadow-[0_0_10px_rgba(249,115,22,0.5)] transition-transform group-hover:scale-110"></div> 
            <span className="font-bold text-slate-300">สูง (Critical Monitoring)</span>
          </div>
          <div className="flex items-center gap-4 group">
            <div className="w-4 h-4 rounded-lg bg-blue-600 shadow-[0_0_10px_rgba(37,99,235,0.5)] transition-transform group-hover:scale-110"></div> 
            <span className="font-bold text-slate-300">ปกติ (Bedbound / Recovery)</span>
          </div>
        </div>
        <div className="pt-3 border-t border-white/10 mt-2">
          <div className="flex items-center gap-4 p-2 rounded-2xl bg-yellow-400/10 border border-yellow-400/20">
            <div className="w-4 h-4 rounded-full border-2 border-yellow-400 bg-yellow-400/20 animate-pulse"></div> 
            <span className="font-black text-yellow-400 uppercase tracking-tighter">Target Impact Zone</span>
          </div>
        </div>
      </div>

      <style>{`
        @keyframes radar-sweep {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }
        .animate-radar-sweep {
          animation: radar-sweep 4s linear infinite;
        }
        .bg-conic-radar {
          background: conic-gradient(from 0deg, rgba(234, 179, 8, 0.4) 0deg, transparent 90deg);
        }
        @keyframes spin-slow {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }
        .animate-spin-slow {
          animation: spin-slow 12s linear infinite;
        }
      `}</style>
    </div>
  );
};

