  const [isFormOpen, setIsFormOpen] = useState(false);
  const [isAssessing, setIsAssessing] = useState(false);
  const [isSimulationEnabled, setIsSimulationEnabled] = useState(true);

  // Planning Mode States
  const [isPlanningMode, setIsPlanningMode] = useState(false);
  const [plannedZone, setPlannedZone] = useState<PlannedOutageZone>({
    center: { lat: 13.7563, lng: 100.5018 },
    radiusKm: 0.8,
    isActive: false
  });

  // Form State
  const [newPatient, setNewPatient] = useState({
    name: '',
    age: '',
    condition: '',
    equipment: [] as string[],
    address: '',
    contact: '',
    lat: 13.75,
    lng: 100.5
  });

  // Outage Simulation Logic
  useEffect(() => {
    if (!isSimulationEnabled) return;
    const interval = setInterval(() => {
      setPatients(prev => {
        if (Math.random() > 0.15) return prev;
        const normalPatients = prev.filter(p => p.status === PowerStatus.NORMAL);
        if (normalPatients.length === 0) return prev;
        const randomIndex = Math.floor(Math.random() * normalPatients.length);
        const targetId = normalPatients[randomIndex].id;
        const durationMinutes = Math.floor(Math.random() * 25) + 5;
        const restorationTime = new Date();
        restorationTime.setMinutes(restorationTime.getMinutes() + durationMinutes);
        return prev.map(p => p.id === targetId ? { 
          ...p, status: PowerStatus.OUTAGE, outageStartTime: new Date().toISOString(),
          estimatedRestorationTime: restorationTime.toISOString(), lastUpdated: new Date().toISOString() 
        } : p);
      });
    }, 25000);
    return () => clearInterval(interval);
  }, [isSimulationEnabled]);

  const handleUpdateStatus = (id: string, status: PowerStatus) => {
    setPatients(prev => prev.map(p => 
      p.id === id ? { ...p, status, lastUpdated: new Date().toISOString() } : p
    ));
  };

  const handleAddPatient = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsAssessing(true);
    const assessment = await assessPatientPriority(newPatient.condition, newPatient.equipment);
    const patient: Patient = {
      id: Math.random().toString(36).substr(2, 9),
      name: newPatient.name,
      age: parseInt(newPatient.age) || 0,
      condition: newPatient.condition,
      equipment: newPatient.equipment,
      address: newPatient.address,
      contact: newPatient.contact,
      coordinates: { lat: newPatient.lat, lng: newPatient.lng },
      priority: assessment.priority as Priority,
      status: PowerStatus.NORMAL,
      lastUpdated: new Date().toISOString()
    };
    setPatients(prev => [patient, ...prev]);
    setIsFormOpen(false);
    setIsAssessing(false);
    setNewPatient({ name: '', age: '', condition: '', equipment: [], address: '', contact: '', lat: 13.75, lng: 100.5 });
  };

  const toggleEquipment = (item: string) => {
    setNewPatient(prev => ({
      ...prev,
      equipment: prev.equipment.includes(item) ? prev.equipment.filter(e => e !== item) : [...prev.equipment, item]
    }));
  };

  // Logic to identify patients in planned zone
  const affectedByPlanning = useMemo(() => {
    if (!plannedZone.isActive) return [];
    return patients.filter(p => {
      const dist = Math.sqrt(
        Math.pow(p.coordinates.lat - plannedZone.center.lat, 2) + 
        Math.pow(p.coordinates.lng - plannedZone.center.lng, 2)
      );
      return dist < (plannedZone.radiusKm * 0.01);
    });
  }, [patients, plannedZone]);

  const totalCritical = patients.filter(p => p.priority === Priority.CRITICAL).length;
  const currentOutages = patients.filter(p => p.status === PowerStatus.OUTAGE).length;

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-['Anuphan']">
      <header className="bg-slate-900 text-white shadow-2xl sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex flex-col sm:flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2.5 rounded-2xl shadow-lg shadow-blue-500/20">
              <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="m6 3 7 7l-2 2l8 8"/><path d="m18 21l-7-7l2-2l-8-8"/></svg>
            </div>
            <div>
              <h1 className="text-xl font-black tracking-tight">LifeLine ElectriGuard</h1>
              <p className="text-[10px] text-slate-400 uppercase tracking-widest font-bold">Preparation & Emergency Monitoring</p>
            </div>
          </div>

          <div className="flex items-center gap-4">
            <div className="hidden md:flex gap-3">
              <div className="bg-slate-800/50 px-4 py-1.5 rounded-xl border border-slate-700 flex flex-col items-center min-w-[90px]">
                <p className="text-[9px] text-slate-500 uppercase font-black tracking-tighter">ผู้ป่วยวิกฤต</p>
                <p className="text-xl font-black text-red-500 leading-none mt-1">{totalCritical}</p>
              </div>
              <div className="bg-slate-800/50 px-4 py-1.5 rounded-xl border border-slate-700 flex flex-col items-center min-w-[90px]">
                <p className="text-[9px] text-slate-500 uppercase font-black tracking-tighter">เหตุไฟดับจริง</p>
                <p className="text-xl font-black text-yellow-500 leading-none mt-1">{currentOutages}</p>
              </div>
            </div>

            <div className="flex gap-2">
              <button 
                onClick={() => {
                  setIsPlanningMode(!isPlanningMode);
                  if (!isPlanningMode) setPlannedZone(prev => ({ ...prev, isActive: true }));
                }}
                className={`px-5 py-2.5 rounded-xl font-black text-xs transition-all flex items-center gap-2 border-2
                  ${isPlanningMode 
                    ? 'bg-yellow-400 border-yellow-500 text-yellow-900 shadow-lg shadow-yellow-400/20' 
                    : 'bg-slate-800 border-slate-700 text-slate-300 hover:bg-slate-700'}`}
              >
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><circle cx="12" cy="12" r="10"/><path d="m16 12-4-4-4 4"/><path d="M12 16V8"/></svg>
                โหมดเตรียมการดับไฟ
              </button>
              <button 
                onClick={() => setIsFormOpen(true)}
                className="bg-blue-600 hover:bg-blue-700 text-white px-5 py-2.5 rounded-xl font-black text-xs transition-all shadow-lg flex items-center gap-2"
              >
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M5 12h14"/><path d="M12 5v14"/></svg>
                ลงทะเบียน
              </button>
            </div>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-7xl mx-auto w-full px-4 sm:px-6 lg:px-8 py-8 grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* Sidebar */}
        <div className="lg:col-span-4 flex flex-col gap-6 order-2 lg:order-1">
          <div className="bg-white p-6 rounded-[32px] shadow-sm border border-slate-200 h-fit">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-lg font-black text-slate-800 flex items-center gap-2">
                <div className={`w-8 h-8 rounded-lg flex items-center justify-center
                  ${isPlanningMode ? 'bg-yellow-100 text-yellow-700' : 'bg-blue-50 text-blue-600'}`}>
                  <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M22 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg>
                </div>
                {isPlanningMode ? 'กลุ่มที่อาจได้รับผลกระทบ' : 'รายชื่อผู้ป่วยทั้งหมด'}
              </h2>
            </div>

            <div className="space-y-4 max-h-[calc(100vh-320px)] overflow-y-auto pr-2 custom-scrollbar">
              {(isPlanningMode ? affectedByPlanning : patients).length === 0 ? (
                <div className="text-center py-20 bg-slate-50 rounded-2xl border border-dashed border-slate-200">
                  <p className="text-slate-400 font-bold text-sm">
                    {isPlanningMode ? 'ไม่มีผู้ป่วยในพื้นที่เป้าหมาย' : 'ยังไม่มีข้อมูลในระบบ'}
                  </p>
                </div>
              ) : (
                (isPlanningMode ? affectedByPlanning : patients).map(p => (
                  <PatientCard key={p.id} patient={p} onUpdateStatus={handleUpdateStatus} />
                ))
              )}
            </div>
          </div>
        </div>

        {/* Map and Prep Tools */}
        <div className="lg:col-span-8 space-y-6 order-1 lg:order-2">

          {/* Enhanced Preparation Control Panel */}
          {isPlanningMode && (
            <div className="bg-slate-900 border border-slate-800 p-8 rounded-[40px] shadow-2xl animate-in slide-in-from-top duration-500">
              <div className="flex flex-col gap-8">
                <div className="flex justify-between items-start">
                  <div>
                    <h3 className="text-2xl font-black text-white uppercase tracking-tight">Maintenance Planning Center</h3>
                    <p className="text-slate-400 text-xs mt-1 font-bold uppercase tracking-widest">Configuration for Planned Power Outage</p>
                  </div>
                  <div className="bg-yellow-500/10 border border-yellow-500/20 px-4 py-2 rounded-2xl">
                    <span className="text-yellow-500 font-black text-xs uppercase">Impact Analysis Active</span>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                  {/* Coordinate Inputs */}
                  <div className="space-y-4">
                     <span className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] block">Target Location</span>
                     <div className="grid grid-cols-2 gap-3">
                        <div className="space-y-1">
                          <label className="text-[9px] text-slate-600 font-black uppercase">Latitude</label>
                          <input 
                            type="number" step="0.0001" 
                            className="w-full bg-slate-800 border-2 border-slate-700 rounded-xl px-3 py-2 text-white font-bold text-sm outline-none focus:border-yellow-500 transition-colors"
                            value={plannedZone.center.lat}
                            onChange={(e) => setPlannedZone(prev => ({ ...prev, center: { ...prev.center, lat: parseFloat(e.target.value) } }))}
                          />
                        </div>
                        <div className="space-y-1">
                          <label className="text-[9px] text-slate-600 font-black uppercase">Longitude</label>
                          <input 
                            type="number" step="0.0001" 
                            className="w-full bg-slate-800 border-2 border-slate-700 rounded-xl px-3 py-2 text-white font-bold text-sm outline-none focus:border-yellow-500 transition-colors"
                            value={plannedZone.center.lng}
                            onChange={(e) => setPlannedZone(prev => ({ ...prev, center: { ...prev.center, lng: parseFloat(e.target.value) } }))}
                          />
                        </div>
                     </div>
                  </div>

                  {/* Radius Slider */}
                  <div className="space-y-4">
                    <div className="flex justify-between items-end">
                      <span className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">Impact Radius</span>
                      <span className="text-yellow-500 font-black text-lg leading-none">{plannedZone.radiusKm.toFixed(1)} <span className="text-[10px]">KM</span></span>
                    </div>
                    <input 
                      type="range" min="0.1" max="5.0" step="0.1"
                      className="w-full accent-yellow-500 cursor-pointer h-2 bg-slate-800 rounded-lg appearance-none"
                      value={plannedZone.radiusKm}
                      onChange={(e) => setPlannedZone(prev => ({ ...prev, radiusKm: parseFloat(e.target.value) }))}
                    />
                  </div>

                  {/* Quick Summary */}
                  <div className="bg-slate-800/50 rounded-3xl p-5 border border-slate-700 flex flex-col justify-center">
                    <div className="flex items-center justify-between mb-2">
                       <span className="text-[10px] font-black text-slate-500 uppercase">Affected Groups</span>
                       <span className="text-white font-black">{affectedByPlanning.length}</span>
                    </div>
                    <div className="flex items-center justify-between">
                       <span className="text-[10px] font-black text-red-500/80 uppercase">Critical Priority</span>
                       <span className="text-red-500 font-black">
                         {affectedByPlanning.filter(p => p.priority === Priority.CRITICAL).length}
                       </span>
                    </div>
                  </div>
                </div>

                <div className="flex gap-4 pt-4 border-t border-slate-800">
                  <button 
                    onClick={() => alert(`แจ้งเตือนผู้ป่วยล่วงหน้าเรียบร้อยแล้ว (${affectedByPlanning.length} ราย)`)}
                    className="flex-1 bg-yellow-500 hover:bg-yellow-600 text-slate-900 font-black py-4 rounded-2xl transition-all shadow-xl shadow-yellow-500/10 active:scale-[0.98] uppercase text-xs"
                    disabled={affectedByPlanning.length === 0}
                  >
                    Broadcast Pre-Maintenance Alert
                  </button>
                  <button 
                    onClick={() => setIsPlanningMode(false)}
                    className="px-6 bg-slate-800 hover:bg-slate-700 text-slate-400 font-black py-4 rounded-2xl transition-all uppercase text-xs"
                  >
                    Exit Planning
                  </button>
                </div>
              </div>
            </div>
          )}

          <div className="bg-white p-2 rounded-[40px] shadow-2xl border border-slate-200 overflow-hidden">
             <PatientMap 
                patients={patients} 
                onSelectPatient={setSelectedPatient}
                plannedZone={plannedZone}
                isPlanningMode={isPlanningMode}
                onMapClick={(lat, lng) => setPlannedZone(prev => ({ ...prev, center: { lat, lng }, isActive: true }))}
             />
          </div>

          {!isPlanningMode && currentOutages > 0 && (
            <div className="bg-red-600 rounded-[32px] p-8 shadow-2xl shadow-red-500/20 text-white animate-pulse">
               <div className="flex items-center gap-4 mb-6">
                 <div className="bg-white/20 p-3 rounded-2xl backdrop-blur-md">
                   <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="m21.73 18l-8-14a2 2 0 0 0-3.48 0l-8 14A2 2 0 0 0 4 21h16a2 2 0 0 0 1.73-3Z"/><path d="M12 9v4"/><path d="M12 17h.01"/></svg>
                 </div>
                 <div>
                   <h3 className="text-2xl font-black uppercase tracking-tight">Active Outage Alert!</h3>
                   <p className="text-red-100 font-bold opacity-90">Emergency support required for {currentOutages} critical locations.</p>
                 </div>
               </div>
               <button className="w-full bg-white text-red-600 font-black py-4 rounded-2xl text-lg hover:bg-red-50 transition-all shadow-xl">
                  Deploy Rapid Response Team
               </button>
            </div>
          )}
        </div>
      </main>

      <footer className="bg-white border-t border-slate-200 py-10 text-center">
        <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.3em]">
          LifeLine ElectriGuard v2.6 // Secure Grid Asset Management
        </p>
      </footer>

      {isFormOpen && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md flex items-center justify-center z-[100] p-4">
           <div className="bg-white rounded-[48px] shadow-2xl max-w-2xl w-full max-h-[90vh] overflow-hidden flex flex-col border border-white/20">
              <div className="p-10 border-b border-slate-100 flex justify-between items-center">
                <h2 className="text-3xl font-black text-slate-900 tracking-tight">Patient Registry</h2>
                <button onClick={() => setIsFormOpen(false)} className="w-14 h-14 flex items-center justify-center rounded-3xl bg-slate-50 text-slate-400 hover:text-red-500 transition-all">
                  <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M18 6 6 18"/><path d="m6 6 12 12"/></svg>
                </button>
              </div>
              <form onSubmit={handleAddPatient} className="p-10 space-y-8 overflow-y-auto custom-scrollbar">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    <div className="space-y-2">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Full Name</label>
                      <input required className="w-full px-6 py-5 rounded-3xl bg-slate-50 border-2 border-transparent focus:border-blue-500 outline-none font-bold" value={newPatient.name} onChange={e => setNewPatient({...newPatient, name: e.target.value})}/>
                    </div>
                    <div className="space-y-2">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Age</label>
                      <input type="number" required className="w-full px-6 py-5 rounded-3xl bg-slate-50 border-2 border-transparent focus:border-blue-500 outline-none font-bold" value={newPatient.age} onChange={e => setNewPatient({...newPatient, age: e.target.value})}/>
                    </div>
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Medical Condition</label>
                    <textarea required className="w-full px-6 py-5 rounded-3xl bg-slate-50 border-2 border-transparent focus:border-blue-500 outline-none font-medium h-32" value={newPatient.condition} onChange={e => setNewPatient({...newPatient, condition: e.target.value})}/>
                  </div>
                  <div className="space-y-4">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Equipment Support</label>
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                      {EQUIPMENT_OPTIONS.map(item => (
                        <button key={item} type="button" onClick={() => toggleEquipment(item)}
                          className={`px-5 py-4 rounded-2xl border-2 text-left text-xs font-bold transition-all
                            ${newPatient.equipment.includes(item) ? 'bg-blue-600 border-blue-600 text-white shadow-xl' : 'bg-white border-slate-100 text-slate-600 hover:border-slate-300'}`}>
                          {item}
                        </button>
                      ))}
                    </div>
                  </div>
                  <button type="submit" disabled={isAssessing} className="w-full py-6 rounded-[32px] bg-blue-600 text-white font-black text-xl hover:bg-blue-700 transition-all shadow-2xl shadow-blue-600/20 active:scale-95">
                    {isAssessing ? 'AI ANALYZING RISK...' : 'REGISTER & ANALYZE'}
                  </button>
              </form>
           </div>
        </div>
      )}

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 8px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e2e8f0; border-radius: 20px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #cbd5e1; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useEffect, useRef } from 'react';
import { Patient, Priority, PlannedOutageZone } from '../types';

interface PatientMapProps {
  patients: Patient[];
  onSelectPatient: (p: Patient) => void;
  plannedZone: PlannedOutageZone;
  onMapClick?: (lat: number, lng: number) => void;
  isPlanningMode: boolean;
}

const PatientMap: React.FC<PatientMapProps> = ({ 
  patients, 
  onSelectPatient, 
  plannedZone, 
  onMapClick,
  isPlanningMode
}) => {
  const mapRef = useRef<HTMLDivElement>(null);
  const googleMap = useRef<google.maps.Map | null>(null);
  const markersRef = useRef<google.maps.Marker[]>([]);
  const circleRef = useRef<google.maps.Circle | null>(null);

  // Initialize Map
  useEffect(() => {
    if (mapRef.current && !googleMap.current) {
      googleMap.current = new google.maps.Map(mapRef.current, {
        center: { lat: 13.7563, lng: 100.5018 },
        zoom: 15,
        mapId: 'DEMO_MAP_ID', // For advanced markers if needed
        disableDefaultUI: false,
        zoomControl: true,
        mapTypeControl: true,
        streetViewControl: false,
        fullscreenControl: true,
        styles: [
          {
            featureType: "all",
            elementType: "geometry.fill",
            stylers: [{ weight: 2.0 }]
          }
        ]
      });

      googleMap.current.addListener('click', (e: google.maps.MapMouseEvent) => {
        if (e.latLng && onMapClick) {
          onMapClick(e.latLng.lat(), e.latLng.lng());
        }
      });
    }
  }, []);

  // Update Markers
  useEffect(() => {
    if (!googleMap.current) return;

    // Clear old markers
    markersRef.current.forEach(m => m.setMap(null));
    markersRef.current = [];

    patients.forEach((p) => {
      const color = p.priority === Priority.CRITICAL ? '#dc2626' : 
                    p.priority === Priority.HIGH ? '#f97316' : '#2563eb';

      const marker = new google.maps.Marker({
        position: p.coordinates,
        map: googleMap.current,
        title: p.name,
        icon: {
          path: google.maps.SymbolPath.CIRCLE,
          fillColor: color,
          fillOpacity: 1,
          strokeColor: '#FFFFFF',
          strokeWeight: 2,
          scale: 12,
        },
        label: {
          text: p.name.charAt(0),
          color: 'white',
          fontSize: '10px',
          fontWeight: 'bold'
        }
      });

      marker.addListener('click', () => onSelectPatient(p));
      markersRef.current.push(marker);
    });
  }, [patients, onSelectPatient]);

  // Update Planned Zone Circle
  useEffect(() => {
    if (!googleMap.current) return;

    if (circleRef.current) {
      circleRef.current.setMap(null);
    }

    if (plannedZone.isActive) {
      circleRef.current = new google.maps.Circle({
        strokeColor: "#eab308",
        strokeOpacity: 0.8,
        strokeWeight: 2,
        fillColor: "#eab308",
        fillOpacity: 0.25,
        map: googleMap.current,
        center: plannedZone.center,
        radius: plannedZone.radiusKm * 1000, // Convert to meters
        clickable: false
      });

      // Optionally pan to center when activated
      // googleMap.current.panTo(plannedZone.center);
    }
  }, [plannedZone]);

  // Sync Map center if plannedZone center changes manually
  useEffect(() => {
    if (googleMap.current && plannedZone.isActive) {
      googleMap.current.panTo(plannedZone.center);
    }
  }, [plannedZone.center]);

  return (
    <div className="relative w-full h-[600px] rounded-[32px] overflow-hidden shadow-inner border-2 border-slate-200">
      <div ref={mapRef} className="w-full h-full" />

      {/* Legend Overlay */}
      <div className="absolute bottom-6 right-6 bg-white/95 backdrop-blur-md p-4 rounded-2xl shadow-xl border border-slate-200 text-[10px] space-y-2 pointer-events-none">
        <div className="font-bold text-slate-800 border-b border-slate-100 pb-2 mb-2 uppercase tracking-wider">
           ระดับความสำคัญของผู้ป่วย
        </div>
        <div className="flex items-center gap-2">
          <div className="w-3 h-3 rounded-full bg-red-600"></div> 
          <span className="font-bold text-slate-600">วิกฤต (ต้องการไฟฟ้าพยุงชีพ)</span>
        </div>
        <div className="flex items-center gap-2">
          <div className="w-3 h-3 rounded-full bg-orange-500"></div> 
          <span className="font-bold text-slate-600">สูง (เฝ้าระวังพิเศษ)</span>
        </div>
        <div className="flex items-center gap-2">
          <div className="w-3 h-3 rounded-full bg-blue-600"></div> 
          <span className="font-bold text-slate-600">ปกติ (ติดเตียงทั่วไป)</span>
        </div>
        {plannedZone.isActive && (
          <div className="pt-2 border-t border-slate-100 mt-2">
            <div className="flex items-center gap-2">
