import React, { useEffect, useRef } from 'react';
import { Patient, Priority, PlannedOutageZone } from '../types';

// Fix: Add global declaration for google to resolve "Cannot find name 'google'"
declare var google: any;

interface PatientMapProps {
  patients: Patient[];
  onSelectPatient: (p: Patient) => void;
  plannedZone: PlannedOutageZone;
  onMapClick?: (lat: number, lng: number) => void;
  isPlanningMode: boolean;
}

const PatientMap: React.FC<PatientMapProps> = ({ 
  patients, 
  onSelectPatient, 
  plannedZone, 
  onMapClick,
  isPlanningMode
}) => {
  const mapRef = useRef<HTMLDivElement>(null);
  // Fix: Use any type to avoid "Cannot find namespace 'google'"
  const googleMap = useRef<any>(null);
  const markersRef = useRef<any[]>([]);
  const circleRef = useRef<any>(null);

  // Initialize Map
  useEffect(() => {
    if (mapRef.current && !googleMap.current) {
      googleMap.current = new google.maps.Map(mapRef.current, {
        center: { lat: 13.7563, lng: 100.5018 },
        zoom: 15,
        mapId: 'DEMO_MAP_ID', // For advanced markers if needed
        disableDefaultUI: false,
        zoomControl: true,
        mapTypeControl: true,
        streetViewControl: false,
        fullscreenControl: true,
        styles: [
          {
            featureType: "all",
            elementType: "geometry.fill",
            stylers: [{ weight: 2.0 }]
          }
        ]
      });

      // Fix: Use any for event type to avoid "Cannot find namespace 'google'"
      googleMap.current.addListener('click', (e: any) => {
        if (e.latLng && onMapClick) {
          onMapClick(e.latLng.lat(), e.latLng.lng());
        }
      });
    }
  }, []);

  // Update Markers
  useEffect(() => {
    if (!googleMap.current) return;

    // Clear old markers
    markersRef.current.forEach(m => m.setMap(null));
    markersRef.current = [];

    patients.forEach((p) => {
      const color = p.priority === Priority.CRITICAL ? '#dc2626' : 
                    p.priority === Priority.HIGH ? '#f97316' : '#2563eb';

      const marker = new google.maps.Marker({
        position: p.coordinates,
        map: googleMap.current,
        title: p.name,
        icon: {
          path: google.maps.SymbolPath.CIRCLE,
          fillColor: color,
          fillOpacity: 1,
          strokeColor: '#FFFFFF',
          strokeWeight: 2,
          scale: 12,
        },
        label: {
          text: p.name.charAt(0),
          color: 'white',
          fontSize: '10px',
          fontWeight: 'bold'
        }
      });

      marker.addListener('click', () => onSelectPatient(p));
      markersRef.current.push(marker);
    });
  }, [patients, onSelectPatient]);

  // Update Planned Zone Circle
  useEffect(() => {
    if (!googleMap.current) return;

    if (circleRef.current) {
      circleRef.current.setMap(null);
    }

    if (plannedZone.isActive) {
      circleRef.current = new google.maps.Circle({
        strokeColor: "#eab308",
        strokeOpacity: 0.8,
        strokeWeight: 2,
        fillColor: "#eab308",
        fillOpacity: 0.25,
        map: googleMap.current,
        center: plannedZone.center,
        radius: plannedZone.radiusKm * 1000, // Convert to meters
        clickable: false
      });

      // Optionally pan to center when activated
      // googleMap.current.panTo(plannedZone.center);
    }
  }, [plannedZone]);

  // Sync Map center if plannedZone center changes manually
  useEffect(() => {
    if (googleMap.current && plannedZone.isActive) {
      googleMap.current.panTo(plannedZone.center);
    }
  }, [plannedZone.center]);

  return (
    <div className="relative w-full h-[600px] rounded-[32px] overflow-hidden shadow-inner border-2 border-slate-200">
      <div ref={mapRef} className="w-full h-full" />

      {/* Legend Overlay */}
      <div className="absolute bottom-6 right-6 bg-white/95 backdrop-blur-md p-4 rounded-2xl shadow-xl border border-slate-200 text-[10px] space-y-2 pointer-events-none">
        <div className="font-bold text-slate-800 border-b border-slate-100 pb-2 mb-2 uppercase tracking-wider">
           ระดับความสำคัญของผู้ป่วย
        </div>
        <div className="flex items-center gap-2">
          <div className="w-3 h-3 rounded-full bg-red-600"></div> 
          <span className="font-bold text-slate-600">วิกฤต (ต้องการไฟฟ้าพยุงชีพ)</span>
        </div>
        <div className="flex items-center gap-2">
